        }
        // IPv6 check (simplified)
        if (host.startsWith("[") || host.contains(":")) {
            return true;
        }
        return false;
    }

    /**
     * Checks if an IP address is private or reserved
     */
    private boolean isPrivateOrReservedIp(String ip) {
        // IPv4 checks
        if (ip.startsWith("127.") || ip.startsWith("0.")) {
            return true;
        }
        if (ip.startsWith("10.")) {
            return true;
        }
        if (ip.startsWith("192.168.")) {
            return true;
        }
        if (ip.startsWith("169.254.")) { // Link-local
            return true;
        }

        // 172.16.0.0/12
        if (ip.startsWith("172.")) {
            String[] parts = ip.split("\\.");
            if (parts.length >= 2) {
                try {
                    int secondOctet = Integer.parseInt(parts[1]);
                    if (secondOctet >= 16 && secondOctet <= 31) {
                        return true;
                    }
                } catch (NumberFormatException e) {
                    // Ignore
                }
            }
        }

        // IPv6 checks
        if (ip.startsWith("::1") || ip.startsWith("0:0:0:0:0:0:0:1")) {
            return true;
        }
        if (ip.startsWith("fe80:") || ip.startsWith("fc00:") || ip.startsWith("fd")) {
            return true;
        }
        if (ip.equals("::")) {
            return true;
        }

        return false;
    }
}

